#include <stdio.h>
#include <string.h>
#define MAXN 1000005
char T[MAXN];
int SA[MAXN], LCP[MAXN];
int cmp(int *r, int a, int b, int l)
{
    return strcmp(r + a, r + b) == 0 ? a + l < strlen(T) && b + l < strlen(T) && r[a + l] < r[b + l] : r[a] < r[b];
}
void make_suffix_array(int *r, char *s, int n)
{
    int *x = (int *)malloc(n * sizeof(int));
    int *y = (int *)malloc(n * sizeof(int));
    int *wa = (int *)malloc(n * sizeof(int));
    int *wb = (int *)malloc(n * sizeof(int));
    int *SA = (int *)malloc(n * sizeof(int));
    int j, p, *t;
    for (int i = 0; i < n; i++) x[i] = i;
    for (int i = 0; i < n; i++) y[i] = s[i];
    for (int i = 0; i < n; i++) wa[i] = wb[i] = 0;
    for (int i = 0; i < n; i++) SA[i] = 0;
    for (j = 1, p = 1; p < n; j *= 2, p *= 2)
    {
        for (int i = 0; i < n; i++) y[i] = i;
        for (int i = (n - j); i < n; i++) y[i - (n - j)] = x[i];
        for (int i = 0; i < n; i++) wa[i] = x[y[i]];
        for (int i = 0; i < n; i++) wb[i] = 0;
        for (int i = 0; i < n; i++) wb[x[i]]++;
        for (int i = 1; i < n; i++) wb[i] += wb[i - 1];
        for (int i = n - 1; i >= 0; i--) SA[--wb[x[y[i]]]] = y[i];
        for (int i = 0; i < n; i++) x[i] = cmp(SA, SA[i], SA[(i + 1) % n], j);
        t = wa; wa = wb; wb = t;
    }
    free(x);
    free(y);
    free(wa);
    free(wb);
}
void make_lcp(int *r, char *s, int n)
{
    int k = 0;
    for (int i = 0; i < n; i++) LCP[i] = 0;
    for (int i = 0; i < n; i++)
    {
        if (k > 0) k--;
        if (r[i] == n - 1)
        {
            k = 0;
            continue;
        }
        for (int j = r[i] + 1; s[j + k] == s[r[i + 1] + k]; k++);
        LCP[r[i]] = k;
    }
}
int main()
{
    int m;
    scanf("%s", T);
    int n = strlen(T);
    make_suffix_array(T, T, n);
    make_lcp(T, T, n);
    scanf("%d", &m);
    for (int i = 0; i < m; i++)
    {
        char query[10];
        scanf("%s", query);
        if (strcmp(query, "Select") == 0)
        {
            int k1, k2;
            scanf("%d %d", &k1, &k2);
            // Find l and r such that T[l..r] are assigned values k1 and k2
            int l = 0, r = 0;
            for (int j = 0; j < n; j++)
            {
                for (int k = j + 1; k <= n; k++)
                {
                    int k1_temp = 0, k2_temp = 0;
                    for (int p = 0; p < n; p++)
                    {
                        if (strcmp(T + j, T + p) < 0)
                        {
                            k1_temp++;
                        }
                        if (strcmp(T + j, T + p) == 0 && p < j)
                        {
                            k2_temp++;
                        }
                    }
                    if (k1_temp == k1 && k2_temp == k2)
                    {
                        l = j + 1;
                        r = k;
                        break;
                    }
                }
                if (l != 0 && r != 0)
                {
                    break;
                }
            }
            printf("%d %d\n", l, r);
        }
        else if (strcmp(query, "Rank") == 0)
        {
            int l, r;
            scanf("%d %d", &l, &r);
            // Calculate k1 and k2 for T[l..r]
            int k1 = 0, k2 = 0;
            for (int j = 0; j < n; j++)
            {
                if (strcmp(T + l - 1, T + j) < 0)
                {
                    k1++;
                }
                if (strcmp(T + l - 1, T + j) == 0 && j < l - 1)
                {
                    k2++;
                }
            }
            printf("%d %d\n", k1, k2);
        }
    }
    return 0;
