#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
using namespace std;
#define MAXN 1000005
string T;
vector<int> SA, LCP;
void make_suffix_array(string &s, vector<int> &SA)
{
    int n = s.size();
    vector<int> x(n), y(n), wa(n), wb(n);
    for (int i = 0; i < n; i++) x[i] = i;
    for (int i = 0; i < n; i++) y[i] = s[i];
    for (int i = 0; i < n; i++) wa[i] = wb[i] = 0;
    for (int j = 1, p = 1; p < n; j *= 2, p *= 2)
    {
        for (int i = 0; i < n; i++) y[i] = i;
        for (int i = (n - j); i < n; i++) y[i - (n - j)] = x[i];
        for (int i = 0; i < n; i++) wa[i] = x[y[i]];
        for (int i = 0; i < n; i++) wb[i] = 0;
        for (int i = 0; i < n; i++) wb[x[i]]++;
        for (int i = 1; i < n; i++) wb[i] += wb[i - 1];
        for (int i = n - 1; i >= 0; i--) SA[--wb[x[y[i]]]] = y[i];
        for (int i = 0; i < n; i++) x[i] = y[i] < y[i + 1] ? -1 : s[y[i]] - s[y[i + 1]];
        swap(wa, wb);
    }
}
void make_lcp(string &s, vector<int> &SA, vector<int> &LCP)
{
    int k = 0;
    for (int i = 0; i < SA.size(); i++) LCP[i] = 0;
    for (int i = 0; i < SA.size(); i++)
    {
        if (k > 0) k--;
        if (SA[i] == s.size() - 1)
        {
            k = 0;
            continue;
        }
        for (int j = SA[i] + 1; s[j + k] == s[SA[i + 1] + k]; k++);
        LCP[SA[i]] = k;
    }
}
