import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String T = scanner.next();
        int n = T.length();
        int m = scanner.nextInt();
        for (int i = 0; i < m; i++) {
            String query = scanner.next();
            if (query.equals("Select")) {
                int k1 = scanner.nextInt();
                int k2 = scanner.nextInt();
                // Find l and r such that T[l..r] are assigned values k1 and k2
                int l = 0, r = 0;
                for (int j = 0; j < n; j++) {
                    for (int k = j + 1; k <= n; k++) {
                        int k1_temp = 0, k2_temp = 0;
                        for (int p = 0; p < n; p++) {
                            if (T.substring(j, k).compareTo(T.substring(p, Math.min(p + k - j, n))) < 0) {
                                k1_temp++;
                            }
                            if (T.substring(j, k).equals(T.substring(p, Math.min(p + k - j, n))) && p < j) {
                                k2_temp++;
                            }
                        }
                        if (k1_temp == k1 && k2_temp == k2) {
                            l = j + 1;
                            r = k;
                            break;
                        }
                    }
                    if (l != 0 && r != 0) {
                        break;
                    }
                }
                System.out.println(l + " " + r);
            } else if (query.equals("Rank")) {
                int l = scanner.nextInt();
                int r = scanner.nextInt();
                // Calculate k1 and k2 for T[l..r]
                int k1 = 0, k2 = 0;
                for (int j = 0; j < n; j++) {
                    if (T.substring(l - 1, r).compareTo(T.substring(j, Math.min(j + r - l + 1, n))) < 0) {
                        k1++;
                    }
                    if (T.substring(l - 1, r).equals(T.substring(j, Math.min(j + r - l + 1, n))) && j < l - 1) {
                        k2++;
                    }
                }
                System.out.println(k1 + " " + k2);
            }
        }
    }
}
